@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle bold
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #000000
skinparam classFontColor #000000
skinparam stereotypeCBackgroundColor #98FB98
skinparam stereotypeCBorderColor #000000
skinparam stereotypeCFontColor #000000
skinparam packageFontStyle bold
skinparam packageBackgroundColor #F5F5F5
skinparam packageBorderColor #000000
skinparam packageFontColor #000000

class "HorizontalMenuRenderer" as HorizontalMenuRenderer {
    <<SuppressWarnings>>
    eapli.framework.presentation.console.menu
}

class "MenuRenderer" as MenuRenderer {
    eapli.framework.presentation.console.menu
}

class "VerticalMenuRenderer" as VerticalMenuRenderer {
    <<SuppressWarnings>>
    eapli.framework.presentation.console.menu
}

class "MenuItemRenderer" as MenuItemRenderer {
    <<SuppressWarnings>>
    eapli.framework.presentation.console.menu
    + MenuItemRenderer DEFAULT
    + MenuItemRenderer()
    + void render(MenuItem item)
}

class "MenuItem" as MenuItem {
    eapli.framework.actions.menu
}

HorizontalMenuRenderer ..> MenuItemRenderer : itemRenderer
MenuRenderer ..> MenuItemRenderer : itemRenderer
VerticalMenuRenderer ..> MenuItemRenderer : itemRenderer
MenuItemRenderer --> MenuItem
MenuItemRenderer --> MenuItemRenderer : DEFAULT

@enduml
